mapper.select:
SELECT COUNT(*) AS totalCount, SUM(CASE WHEN status = 2 THEN 1 ELSE 0 END) AS paidCount, SUM(CASE WHEN status = 3 THEN 1 ELSE 0 END) AS refundedCount, COALESCE(SUM(CASE WHEN status IN (2, 3) THEN amount ELSE 0 END), 0) AS totalAmount, COALESCE(SUM(CASE WHEN status = 3 THEN refund_amount ELSE 0 END), 0) AS totalRefund FROM sparkit_payment_order WHERE deleted = 0
AND create_time >= #{startTime}
AND create_time <= #{endTime}
